<?php require_once 'config/db.php'; require_once 'includes/auth.php'; $role=$_GET['role']??'user'; if(!in_array($role,['admin','user']))$role='user'; $error=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $u=trim($_POST['username']); $p=$_POST['password']; $stmt=mysqli_prepare($conn,'SELECT * FROM APP_USER WHERE username=? AND role=? LIMIT 1'); mysqli_stmt_bind_param($stmt,'ss',$u,$role); mysqli_stmt_execute($stmt); $user=mysqli_fetch_assoc(mysqli_stmt_get_result($stmt)); if($user && password_verify($p,$user['password_hash'])){ $_SESSION['user_id']=$user['user_id']; $_SESSION['username']=$user['username']; $_SESSION['full_name']=$user['full_name']; $_SESSION['role']=$user['role']; header('Location: dashboard.php'); exit(); } else $error='Invalid username or password.'; } ?>
<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Login</title><link rel="stylesheet" href="assets/css/style.css"></head><body class="auth-body"><form class="auth-card" method="POST"><h1><?= ucfirst($role) ?> Login</h1><p>Enter your username and password.</p><?php if($error): ?><div class="alert alert-error"><?= safe($error) ?></div><?php endif; ?><label>Username</label><input class="input" name="username" required><label>Password</label><input class="input" type="password" name="password" required><button class="btn">Login</button> <a class="btn btn-light" href="index.php">Back</a><?php if($role==='user'): ?><p style="margin-top:16px">No account? <a href="signup.php">Sign up</a></p><?php else: ?><p style="margin-top:16px;font-size:13px">Admin: <strong>admin</strong> / <strong>admin123</strong></p><?php endif; ?></form></body></html>
